"use client";
import * as React from "react";
import { motion, useMotionTemplate, useScroll, useTransform } from "framer-motion";

interface SmoothScrollHeroProps {
  scrollHeight?: number;
  desktopImage?: string;
  mobileImage?: string;
  initialClipPercentage?: number;
  finalClipPercentage?: number;
}

export function SmoothScrollHero({
  scrollHeight = 1500,
  desktopImage = "https://images.unsplash.com/photo-1511884642898-4c92249e20b6",
  mobileImage = "https://images.unsplash.com/photo-1511207538754-e8555f2bc187?q=80&w=2412&auto=format&fit=crop",
  initialClipPercentage = 25,
  finalClipPercentage = 75,
}: SmoothScrollHeroProps) {
  const containerRef = React.useRef<HTMLDivElement>(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"],
  });

  const clipStart = useTransform(scrollYProgress, [0, 1], [initialClipPercentage, 0]);
  const clipEnd = useTransform(scrollYProgress, [0, 1], [finalClipPercentage, 100]);
  const backgroundSize = useTransform(scrollYProgress, [0, 1], ["170%", "100%"]);

  // clipEnd goes 75→100, so bottom inset = 100 - clipEnd goes 25→0
  const clipBottom = useTransform(clipEnd, (v: number) => 100 - v);
  const clipPath = useMotionTemplate`inset(${clipStart}% 0 ${clipBottom}% 0)`;


  return (
    <div
      ref={containerRef}
      className="relative w-full"
      style={{ height: `calc(${scrollHeight}px + 100vh)` }}
    >
      <div
        style={{
          position: "sticky",
          top: 0,
          height: "100vh",
          overflow: "hidden",
          background: "transparent",
        }}
      >
        {/* image with clip-path reveal and backgroundSize zoom */}
        <motion.div
          style={{
            clipPath,
            position: "absolute",
            inset: 0,
          }}
        >
          {/* desktop */}
          <motion.div
            className="hidden sm:block"
            style={{
              width: "100%",
              height: "100%",
              backgroundImage: `url(${desktopImage}?w=1800&auto=format&fit=crop)`,
              backgroundSize,
              backgroundPosition: "center",
              backgroundRepeat: "no-repeat",
            }}
          />
          {/* mobile */}
          <motion.div
            className="block sm:hidden"
            style={{
              width: "100%",
              height: "100%",
              backgroundImage: `url(${mobileImage})`,
              backgroundSize,
              backgroundPosition: "center",
              backgroundRepeat: "no-repeat",
            }}
          />
          {/* overlay */}
          <div
            style={{
              position: "absolute",
              inset: 0,
              background: "linear-gradient(to top, rgba(0,0,0,0.45) 0%, rgba(0,0,0,0.05) 60%)",
            }}
          />
        </motion.div>

      </div>
    </div>
  );
}
