'use client';

import { useState } from 'react';

const accordionItems = [
  { id: 1, title: 'Film', imageUrl: 'https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=800&auto=format&fit=crop' },
  { id: 2, title: 'Creative Brief', imageUrl: 'https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=800&auto=format&fit=crop' },
  { id: 3, title: 'Internet Literature', imageUrl: 'https://images.unsplash.com/photo-1456513080510-7bf3a84b82f8?w=800&auto=format&fit=crop' },
  { id: 4, title: 'Games', imageUrl: 'https://images.unsplash.com/photo-1511512578047-dfb367046420?w=800&auto=format&fit=crop' },
  { id: 5, title: 'TV Series', imageUrl: 'https://images.unsplash.com/photo-1503095396549-807759245b35?w=800&auto=format&fit=crop' },
];

export function LandingAccordionItem() {
  const [activeId, setActiveId] = useState<number>(1);

  return (
    <div
      style={{
        flex: '0 0 auto',
        display: 'flex',
        flexDirection: 'row',
        height: '450px',
        gap: '5px',
        overflow: 'hidden',
        paddingRight: '80px',
        marginLeft: '100px',
      }}
    >
      {accordionItems.map((item) => {
        const isActive = activeId === item.id;
        return (
          <div
            key={item.id}
            onMouseEnter={() => setActiveId(item.id)}
            style={{
              width: isActive ? '400px' : '60px',
              flex: '0 0 auto',
              transition: 'width 0.6s cubic-bezier(0.4, 0, 0.2, 1)',
              borderRadius: '10px',
              overflow: 'hidden',
              cursor: 'pointer',
              position: 'relative',
              pointerEvents: 'auto',
            }}
          >
            {/* background image */}
            <div
              style={{
                position: 'absolute',
                inset: 0,
                backgroundImage: `url(${item.imageUrl})`,
                backgroundSize: 'cover',
                backgroundPosition: 'center',
                transition: 'transform 0.6s cubic-bezier(0.4, 0, 0.2, 1)',
                transform: isActive ? 'scale(1.04)' : 'scale(1)',
              }}
            />
            {/* dark overlay */}
            <div
              style={{
                position: 'absolute',
                inset: 0,
                background: isActive
                  ? 'linear-gradient(to top, rgba(0,0,0,0.58) 0%, rgba(0,0,0,0.04) 60%)'
                  : 'rgba(0,0,0,0.30)',
                transition: 'background 0.6s ease',
              }}
            />
            {/* title */}
            <div
              style={{
                position: 'absolute',
                bottom: '14px',
                left: 0,
                right: 0,
                display: 'flex',
                alignItems: 'flex-end',
                justifyContent: isActive ? 'flex-start' : 'center',
                padding: isActive ? '0 14px' : '0',
                transition: 'all 0.4s ease',
                overflow: 'hidden',
              }}
            >
              <span
                style={{
                  fontFamily: "'Adobe Song Std', 'AdobeSongStd', serif",
                  fontSize: isActive ? '20px' : '10px',
                  fontWeight: 700,
                  color: 'rgba(255,255,255,0.93)',
                  letterSpacing: '0.12em',
                  writingMode: isActive ? 'horizontal-tb' : 'vertical-rl',
                  textOrientation: 'mixed',
                  transition: 'all 0.4s ease',
                  textShadow: '0 1px 4px rgba(0,0,0,0.45)',
                  transform: isActive ? 'none' : 'rotate(180deg)',
                  whiteSpace: 'nowrap',
                }}
              >
                {item.title}
              </span>
            </div>
          </div>
        );
      })}
    </div>
  );
}
